import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.BWuWLRhz.js";const i="/assets/cases/liduoxing/user-segmentation/customer-segmentation-framework.png",u=JSON.parse('{"title":"用户分层与客户经营分析","description":"","frontmatter":{},"headers":[],"relativePath":"projects/liduoxing/user-tags.md","filePath":"projects/liduoxing/user-tags.md"}'),s={name:"projects/liduoxing/user-tags.md"};function n(l,t,o,h,p,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="用户分层与客户经营分析" tabindex="-1">用户分层与客户经营分析 <a class="header-anchor" href="#用户分层与客户经营分析" aria-label="Permalink to &quot;用户分层与客户经营分析&quot;">​</a></h1><blockquote><p>用户分层与客户经营分析是围绕五星智投客户生命周期搭建的数据产品项目。它通过订单、退款、埋点、用户账户和服务数据，将客户从“单点用户记录”组织成 <span class="text-highlight-blue">可分层、可运营、可分析、可复盘</span> 的生命周期数据资产。</p></blockquote><div class="project-snapshot"><div><strong>生命周期</strong><span>1.0 / 2.0 / 3.0、升级、续费、召回、流失预警</span></div><div><strong>ID 映射</strong><span>埋点用户、账户用户、订单客户之间的映射链路</span></div><div><strong>客户宽表</strong><span>服务周期、退款、在期、活跃、服务归因</span></div><div><strong>运营标签</strong><span>基础、行为、价值、产品适配、风险与忠诚度</span></div></div><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>金融业务中的客户会经历注册、低价产品、升级、复购、续费、退款、沉默、召回等多个阶段。</p><p>如果只看订单表或单一用户表，业务很难判断：</p><ul><li>客户当前是否在期？</li><li>客户是否活跃，最近是否访问核心服务页面？</li><li>客户是否有升级、续费、召回价值？</li><li>哪些客户正在流失或有退款风险？</li><li>服务动作、产品使用和支付转化之间是否有关联？</li><li>员工和团队应该把精力优先放在哪些客户上？</li></ul><p>因此，需要通过客户分层和用户分析，把用户行为、交易、服务和生命周期统一起来。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ol><li>建立客户生命周期分层口径，覆盖 1.0、2.0、3.0、流失预警等阶段。</li><li>建立用户分层体系，支持基础、行为、价值、产品适配、忠诚度和风险识别。</li><li>打通埋点用户、账户用户、订单客户之间的 ID 映射。</li><li>设计客户服务宽表和用户活跃宽表，为 BI 指标和运营策略提供底层数据。</li><li>支持升级、续费、召回、客户净增、退款和 LTV 分析。</li></ol><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>我负责用户分层框架、客户生命周期分析、ID 映射逻辑和客户宽表方案梳理。这个项目要求我从业务策略出发，回到数据表和字段层面设计可执行的数据集。</p><table tabindex="0"><thead><tr><th>工作方向</th><th>我承担的工作</th></tr></thead><tbody><tr><td>生命周期分层</td><td>梳理 1.0 / 2.0 / 3.0、升级、续费、流失预警等客户阶段</td></tr><tr><td>分层体系</td><td>设计单标签和复合标签，覆盖活跃、价值、产品适配、忠诚度、风险</td></tr><tr><td>ID 映射</td><td>梳理埋点 <code>short_user_code</code>、账户 <code>union_id</code>、订单客户编码之间的映射链路</td></tr><tr><td>宽表设计</td><td>设计客户服务宽表、用户活跃宽表和 BI 指标配置方式</td></tr><tr><td>业务策略</td><td>将标签映射到升级、续费、召回、资源分配和客户运营场景</td></tr></tbody></table><h2 id="生命周期框架" tabindex="-1">生命周期框架 <a class="header-anchor" href="#生命周期框架" aria-label="Permalink to &quot;生命周期框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>核心目标</th><th>重点标签</th><th>运营策略</th></tr></thead><tbody><tr><td>1.0 会员</td><td>激活和首单转化</td><td>活跃、首单转化、价格敏感、低忠诚</td><td>新手引导、体验权益、教育内容</td></tr><tr><td>2.0 会员</td><td>升级和复购</td><td>使用深度、客单价、复购频次、中忠诚</td><td>升级权益、促活提醒、套餐设计</td></tr><tr><td>3.0 会员</td><td>提升 LTV 和留存</td><td>高频使用、高客单、LTV、高忠诚</td><td>专属服务、VIP 运营、权益升级</td></tr><tr><td>流失预警</td><td>召回和风险干预</td><td>活跃下降、消费下降、N 天未活跃、忠诚下降</td><td>召回激励、重点回访、定向优惠</td></tr></tbody></table><h2 id="用户分层框架" tabindex="-1">用户分层框架 <a class="header-anchor" href="#用户分层框架" aria-label="Permalink to &quot;用户分层框架&quot;">​</a></h2><p>这个项目的核心是把客户拆成可以服务经营决策的分层体系。分层要能回答：客户现在处于什么阶段，是否活跃，资产和贡献价值如何，风险偏好是什么，适合推荐什么产品，以及是否值得继续投入服务资源。</p><div class="case-image-grid"><figure><img src="'+i+`" alt="用户分层与客户经营分析框架"><figcaption><strong>用户分层体系：从客户识别走向客户经营</strong><span>围绕基础信息、行为活跃、资产价值、风险偏好、产品偏好和忠诚度六个方向建立分层，进一步匹配开户转化、交易促活、产品推荐、风险适配、续费召回和老带新等运营场景。</span></figcaption></figure></div><h2 id="标签体系" tabindex="-1">标签体系 <a class="header-anchor" href="#标签体系" aria-label="Permalink to &quot;标签体系&quot;">​</a></h2><p>标签的价值在于帮助业务识别不同客户该采取什么动作。上面的分层框架负责定义客户经营视角，具体落地时再拆成可计算、可筛选、可复盘的标签。</p><table tabindex="0"><thead><tr><th>标签维度</th><th>示例标签</th><th>业务用途</th></tr></thead><tbody><tr><td>基础属性</td><td>产品层级、客户状态、服务周期、团队归属</td><td>判断客户属于哪类经营对象</td></tr><tr><td>行为标签</td><td>登录、浏览、观看、点击、互动、N 天未活跃</td><td>判断产品使用深度和活跃变化</td></tr><tr><td>价值标签</td><td>客单价、复购、LTV、退款率、净价值</td><td>判断客户投入和服务优先级</td></tr><tr><td>产品适配</td><td>适合升级、适合续费、适合召回、无价值</td><td>支持差异化运营</td></tr><tr><td>风险标签</td><td>退款风险、投诉风险、服务未覆盖、流失预警</td><td>支持风险前置识别</td></tr><tr><td>忠诚度</td><td>高频使用、高传播、低流失、沉默客户</td><td>支持长期客户经营</td></tr></tbody></table><h2 id="数据集设计" tabindex="-1">数据集设计 <a class="header-anchor" href="#数据集设计" aria-label="Permalink to &quot;数据集设计&quot;">​</a></h2><p>项目中设计了两个关键数据集。</p><h3 id="客户服务宽表" tabindex="-1">客户服务宽表 <a class="header-anchor" href="#客户服务宽表" aria-label="Permalink to &quot;客户服务宽表&quot;">​</a></h3><p>用于总服务用户、在期用户、客户净增和退款分析。</p><table tabindex="0"><thead><tr><th>字段类型</th><th>代表字段</th><th>用途</th></tr></thead><tbody><tr><td>客户维度</td><td>客户编码、union_id、客户名称</td><td>统一客户对象</td></tr><tr><td>订单维度</td><td>订单号、产品、产品组、实付金额</td><td>判断客户购买内容</td></tr><tr><td>时间维度</td><td>支付时间、服务开始、服务结束</td><td>判断是否在期和服务周期</td></tr><tr><td>退款维度</td><td>是否退款、退款时间、退款金额、退款原因</td><td>判断退款风险和经营结果</td></tr><tr><td>归因维度</td><td>员工、部门、中心、团队</td><td>支持服务归因和团队复盘</td></tr></tbody></table><h3 id="用户活跃宽表" tabindex="-1">用户活跃宽表 <a class="header-anchor" href="#用户活跃宽表" aria-label="Permalink to &quot;用户活跃宽表&quot;">​</a></h3><p>用于计算整体活跃率和在期活跃率。</p><table tabindex="0"><thead><tr><th>数据链路</th><th>作用</th></tr></thead><tbody><tr><td>埋点 <code>short_user_code</code></td><td>从行为数据识别用户</td></tr><tr><td>用户账户 <code>union_id</code></td><td>将行为用户映射到账户用户</td></tr><tr><td>订单客户编码</td><td>将账户用户映射到真实客户</td></tr><tr><td>活跃日期和事件数</td><td>判断客户是否在服务期内发生行为</td></tr></tbody></table><p>这个映射链路很关键，它让埋点行为可以真正回到客户和订单层面。</p><h2 id="数据难点" tabindex="-1">数据难点 <a class="header-anchor" href="#数据难点" aria-label="Permalink to &quot;数据难点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>难点</th><th>具体表现</th><th>处理方式</th></tr></thead><tbody><tr><td>退款一单多笔</td><td>同一订单可能有多条退款记录</td><td>先按订单聚合，再与订单表关联</td></tr><tr><td>ID 匹配</td><td>埋点用户、账户用户、订单客户使用不同 ID</td><td>通过 short_user_code -&gt; union_id -&gt; 客户编码映射</td></tr><tr><td>三端区分</td><td>某些埋点字段无法稳定区分 APP / 小程序</td><td>先做整体活跃率，待字段明确后再拆三端</td></tr><tr><td>数据量膨胀</td><td>活跃宽表按客户和日期展开，行数可能很大</td><td>评估性能，必要时拆分数据集或使用关联分析</td></tr><tr><td>生命周期口径</td><td>在期、到期、退款、升级窗口定义复杂</td><td>将业务规则写入字段和筛选条件</td></tr></tbody></table><h2 id="数据如何驱动" tabindex="-1">数据如何驱动 <a class="header-anchor" href="#数据如何驱动" aria-label="Permalink to &quot;数据如何驱动&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>订单 / 退款</span></span>
<span class="line"><span>  -&gt; 客户状态</span></span>
<span class="line"><span>  -&gt; 埋点行为</span></span>
<span class="line"><span>  -&gt; 活跃与服务覆盖</span></span>
<span class="line"><span>  -&gt; 标签分层</span></span>
<span class="line"><span>  -&gt; 升级 / 续费 / 召回 / 风险处理</span></span></code></pre></div><p>客户标签的价值，是让业务能从“这个客户买过什么”继续判断“这个客户现在处于什么阶段，下一步应该做什么”。</p><h2 id="成果与价值" tabindex="-1">成果与价值 <a class="header-anchor" href="#成果与价值" aria-label="Permalink to &quot;成果与价值&quot;">​</a></h2><ul><li>建立客户生命周期分析框架，覆盖阶段分层、标签体系和运营策略。</li><li>梳理客户服务宽表和用户活跃宽表，为 BI 和客户运营提供底层数据。</li><li>打通埋点、账户、订单之间的 ID 映射链路。</li><li>明确退款聚合、服务周期、在期活跃率等关键口径。</li><li>支撑私享家 BI、客户分析、服务复盘和精细化运营。</li></ul><h2 id="个人能力沉淀" tabindex="-1">个人能力沉淀 <a class="header-anchor" href="#个人能力沉淀" aria-label="Permalink to &quot;个人能力沉淀&quot;">​</a></h2><p>这个项目体现了 <span class="text-highlight-warm">用户分层和数据资产设计能力</span>。标签体系需要让客户状态、行为、价值和风险能被业务持续使用。</p>`,39)])])}const g=d(s,[["render",n]]);export{u as __pageData,g as default};
